func testAccMigrationCenterImportJob_migrationCenterImportJobBasicExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
resource "google_migration_center_source" "default" {
  location  = "us-central1"
  source_id = "%{source_id}"
  type      = "SOURCE_TYPE_CUSTOM"
}

resource "google_migration_center_import_job" "default" {
  location      = "us-central1"
  import_job_id = "%{import_job_id}"
  asset_source  = google_migration_center_source.default.id
  display_name  = "%{display_name}"
  labels = {
    my_key     = "%{label_value}"
    second_key = "second_value"
  }
}
`, context)
}

func testAccCheckMigrationCenterImportJobDestroyProducer(t *testing.T) func(s *terraform.State) error {
	return func(s *terraform.State) error {
		for name, rs := range s.RootModule().Resources {
			if rs.Type != "google_migration_center_import_job" {
				continue
			}
			if strings.HasPrefix(name, "data.") {
				continue
			}

			config := acctest.GoogleProviderConfig(t)
			url, err := tpgresource.ReplaceVarsForTest(config, rs, transport_tpg.BaseUrl(migrationcenter.Product, config)+"projects/{{project}}/locations/{{location}}/importJobs/{{import_job_id}}")
			if err != nil {
				return err
			}

			billingProject := ""

			if config.BillingProject != "" {
				billingProject = config.BillingProject
			}

			_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: config.UserAgent,
			})
			if err == nil {
				return fmt.Errorf("MigrationCenterImportJob still exists at %s", url)
			}
		}

		return nil
	}
}
